const WORDS = [...WORDS_EN, ...WORDS_ES];

// FNV-1a inspired hash
function hashStr(s) {
  let h = 0x811c9dc5;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = (h * 0x01000193) >>> 0;
  }
  return h;
}

function getWordsOfDay(count = 5, dateStr = null, lang = null) {
  const date = dateStr || new Date().toISOString().slice(0, 10);
  const seed = hashStr(date);
  let pool = lang ? WORDS.filter(w => w.lang === lang) : WORDS;
  const shuffled = [...pool].sort((a, b) => {
    const ha = (seed ^ hashStr(a.id)) >>> 0;
    const hb = (seed ^ hashStr(b.id)) >>> 0;
    return ha - hb;
  });
  return shuffled.slice(0, count);
}

function getRandomWords(count = 5, lang = null) {
  let pool = lang ? WORDS.filter(w => w.lang === lang) : WORDS;
  const copy = [...pool];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy.slice(0, count);
}

function getRandomWord(lang = null) {
  const pool = lang ? WORDS.filter(w => w.lang === lang) : WORDS;
  return pool[Math.floor(Math.random() * pool.length)];
}

function getWordById(id) {
  return WORDS.find((w) => w.id === id) || null;
}

function getQuizQuestion(lang = null) {
  const word = getRandomWord(lang);
  const pool = lang ? WORDS.filter(w => w.lang === lang) : WORDS;
  const others = pool.filter((w) => w.id !== word.id);
  const wrong = [];
  const usedTranslations = new Set([word.translation]);
  const shuffledOthers = [...others].sort(() => Math.random() - 0.5);
  for (const w of shuffledOthers) {
    if (wrong.length >= 3) break;
    if (!usedTranslations.has(w.translation)) {
      wrong.push(w.translation);
      usedTranslations.add(w.translation);
    }
  }
  const options = [{ text: word.translation, correct: true }, ...wrong.map((t) => ({ text: t, correct: false }))];
  for (let i = options.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [options[i], options[j]] = [options[j], options[i]];
  }
  const correctIndex = options.findIndex((o) => o.correct);
  const optionsWithData = options.map((o, idx) => ({
    text: o.text,
    callbackData: `quiz_${word.id}__${correctIndex}__${idx}`.slice(0, 64),
  }));
  return { word, options: optionsWithData, correctIndex };
}

export { WORDS, WORDS_EN, WORDS_ES, getWordsOfDay, getRandomWords, getRandomWord, getWordById, getQuizQuestion };
